import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const [showPass, setShowPass] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault(); setError(''); setLoading(true);
    try {
      const data = await login(email, password);
      navigate(data.user.role === 'admin' ? '/admin/dashboard' : '/student/dashboard');
    } catch (err) {
      setError(err.response?.data?.message || 'Invalid email or password');
    } finally { setLoading(false); }
  };

  return (
    <div className="login-page">
      <div className="login-left">
        <div className="login-card">
          <div className="login-logo">
            <span className="emoji">🚌</span>
            <h1>Campus Bus Fees</h1>
            <p>Sign in to your account</p>
          </div>
          {error && <div className="login-error">⚠️ {error}</div>}
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label>Email Address</label>
              <div className="login-input-group">
                <span className="login-input-icon">📧</span>
                <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="your@email.com" required />
              </div>
            </div>
            <div className="form-group">
              <label>Password</label>
              <div className="login-input-group">
                <span className="login-input-icon">🔒</span>
                <input type={showPass ? 'text' : 'password'} value={password} onChange={e => setPassword(e.target.value)} placeholder="Enter password" required style={{ paddingRight: 44 }} />
                <button type="button" onClick={() => setShowPass(!showPass)} style={{ position:'absolute', right:12, top:'50%', transform:'translateY(-50%)', background:'none', border:'none', cursor:'pointer', fontSize:16 }}>{showPass ? '🙈' : '👁️'}</button>
              </div>
            </div>
            <button type="submit" className="btn btn-primary btn-lg" style={{ width:'100%', justifyContent:'center', marginTop:8 }} disabled={loading}>
              {loading ? <><span className="spinner" style={{ width:16, height:16, borderWidth:2 }} /> Signing in...</> : '🔐 Sign In'}
            </button>
          </form>
          <div style={{ marginTop:24, background:'#f0f9ff', border:'1px solid #bae6fd', borderRadius:10, padding:14 }}>
            <div style={{ fontSize:11, fontWeight:700, color:'#0369a1', marginBottom:8, textTransform:'uppercase', letterSpacing:1 }}>Demo Access</div>
            <div style={{ fontSize:12, color:'#0c4a6e' }}>
              <div>👨‍💼 <strong>Admin:</strong> admin@college.edu / Admin@123</div>
            </div>
          </div>
        </div>
      </div>
      <div className="login-right">
        <div className="login-info">
          <h2>🚌 Smart Bus Fee Management</h2>
          <p>A complete solution for managing college bus transportation fees — track payments, set schedules, and keep students informed.</p>
          <div className="login-features">
            {[
              ['📊', 'Real-time dashboard with analytics'],
              ['💰', 'Bulk fee generation & collection'],
              ['📅', 'Payment schedule management'],
              ['🔔', 'Automated payment reminders'],
              ['🧾', 'Digital receipts & reports'],
              ['👨‍🎓', 'Student self-service portal'],
            ].map(([icon, text]) => (
              <div className="login-feat" key={text}>
                <span className="icon">{icon}</span>
                <span>{text}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
